#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[100005];
        scanf("%100004s", s);
        int n = strlen(s);
        char out[100005];
        int idx = 0, depth = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == '(') {
                if (depth > 0) out[idx++] = '(';
                depth++;
            } else { // ')'
                depth--;
                if (depth > 0) out[idx++] = ')';
            }
        }
        out[idx] = '\0';
        printf("%s\n", out);
    }
    return 0;
}

