using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T; 
    if(!(cin>>T)) return 0;
    while(T--) {
        string s; 
        cin >> s; // no spaces in the string
        string res;
        res.reserve(s.size());
        int depth = 0;
        for(char ch: s){
            if(ch=='('){
                if(depth>0) res.push_back(ch);
                ++depth;
            }else{ // ')'
                --depth;
                if(depth>0) res.push_back(ch);
            }
        }
        cout << res << '\n';
    }
    return 0;
}

