import sys

def remove_outer(s: str) -> str:
    res = []
    depth = 0
    for ch in s:
        if ch == '(':
            if depth > 0:
                res.append(ch)
            depth += 1
        else:
            depth -= 1
            if depth > 0:
                res.append(ch)
    return ''.join(res)

data = sys.stdin.read().splitlines()
if not data:
    sys.exit()
T = int(data[0].strip())
out_lines = []
for i in range(1, T+1):
    s = data[i].strip()
    out_lines.append(remove_outer(s))
print('\n'.join(out_lines))

